using System.Reflection;

var basePath = "/home/runner/.nuget/packages/";
var dlls = new[] {
    "microsoft.agents.ai.abstractions/1.3.0/lib/net10.0/Microsoft.Agents.AI.Abstractions.dll",
    "microsoft.agents.ai/1.3.0/lib/net10.0/Microsoft.Agents.AI.dll",
};

// Load dependencies first
var deps = new[] {
    "microsoft.extensions.ai.abstractions/10.5.0/lib/net10.0/Microsoft.Extensions.AI.Abstractions.dll",
    "microsoft.extensions.ai/10.5.0/lib/net10.0/Microsoft.Extensions.AI.dll",
};

foreach (var d in deps)
{
    try { Assembly.LoadFrom(Path.Combine(basePath, d)); } catch {}
}

foreach (var d in dlls)
{
    var asm = Assembly.LoadFrom(Path.Combine(basePath, d));
    Console.WriteLine($"\n=== {Path.GetFileName(d)} ===");
    foreach (var t in asm.GetExportedTypes().OrderBy(t => t.FullName))
    {
        Console.WriteLine($"\n{(t.IsInterface ? "interface" : t.IsAbstract ? "abstract class" : "class")} {t.FullName}");
        if (t.BaseType != null && t.BaseType != typeof(object))
            Console.WriteLine($"  : {t.BaseType.FullName}");
        foreach (var iface in t.GetInterfaces())
            Console.WriteLine($"  implements {iface.Name}");
        foreach (var c in t.GetConstructors())
            Console.WriteLine($"  ctor({string.Join(", ", c.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
        foreach (var p in t.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
            Console.WriteLine($"  prop {p.PropertyType.Name} {p.Name}");
        foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly).Where(m => !m.IsSpecialName))
            Console.WriteLine($"  {m.ReturnType.Name} {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
    }
}
