using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to your OpenAI API key.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Build the chat client ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Create tools ---
var notepad = new Notepad();
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("Mozilla/5.0 (compatible; ResearchAgent/1.0)");
httpClient.Timeout = TimeSpan.FromSeconds(15);
var webSearch = new WebSearchTool(httpClient);

List<AITool> tools =
[
    AIFunctionFactory.Create(webSearch.SearchAsync),
    AIFunctionFactory.Create(webSearch.FetchPageAsync),
    AIFunctionFactory.Create(notepad.SaveNote),
    AIFunctionFactory.Create(notepad.GetAllNotes),
];

// --- Create the agent ---
var agent = chatClient.AsAIAgent(
    instructions: """
        You are a thorough research agent. When given a topic:

        1. Search the web with 2-3 different queries to gather diverse perspectives.
        2. For the most promising results, fetch full page content for details.
        3. Save important findings as notes with clear titles.
        4. After gathering enough information (at least 3 notes), retrieve all notes.
        5. Synthesize your notes into a well-structured summary with:
           - An overview of the topic
           - Key findings organized by theme
           - Sources cited

        Be thorough but efficient. Focus on factual, well-sourced information.
        """,
    name: "ResearchAgent",
    description: "Researches topics by searching the web and summarizing findings",
    tools: tools);

// --- Get topic and run ---
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");
Console.WriteLine(new string('-', 60));

var session = await agent.CreateSessionAsync();

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic thoroughly and provide a comprehensive summary: {topic}",
    session))
{
    if (update.Text is { } text)
    {
        Console.Write(text);
    }
}

Console.WriteLine();
Console.WriteLine(new string('-', 60));
Console.WriteLine($"\n{notepad.Count} note(s) were taken during research.");

