using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;

/// <summary>
/// Provides web search and page fetching capabilities for the research agent.
/// Uses DuckDuckGo HTML search (no API key required).
/// </summary>
public sealed class WebSearchTool(HttpClient httpClient)
{
    [Description("Search the web for information. Returns the top results with titles, URLs, and snippets.")]
    public async Task<string> SearchAsync(
        [Description("The search query to look up")] string query)
    {
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";
            var html = await httpClient.GetStringAsync(url);
            return ParseSearchResults(html);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }

    [Description("Fetch and read the text content of a web page at the given URL.")]
    public async Task<string> FetchPageAsync(
        [Description("The full URL of the web page to fetch")] string url)
    {
        try
        {
            var html = await httpClient.GetStringAsync(url);
            var text = StripHtml(html);

            const int maxLength = 4000;
            return text.Length > maxLength
                ? string.Concat(text.AsSpan(0, maxLength), "\n[Content truncated]")
                : text;
        }
        catch (Exception ex)
        {
            return $"Failed to fetch page: {ex.Message}";
        }
    }

    private static string ParseSearchResults(string html)
    {
        var sb = new StringBuilder();
        int count = 0;

        // Match DuckDuckGo HTML result blocks
        var linkPattern = new Regex(
            @"<a[^>]+class=""result__a""[^>]*href=""(?<href>[^""]+)""[^>]*>(?<title>.*?)</a>",
            RegexOptions.Singleline);

        var snippetPattern = new Regex(
            @"<a[^>]+class=""result__snippet""[^>]*>(?<snippet>.*?)</a>",
            RegexOptions.Singleline);

        var links = linkPattern.Matches(html);
        var snippets = snippetPattern.Matches(html);

        for (int i = 0; i < links.Count && count < 8; i++)
        {
            count++;
            var title = StripHtml(links[i].Groups["title"].Value).Trim();
            var href = WebUtility.HtmlDecode(links[i].Groups["href"].Value).Trim();
            var snippet = i < snippets.Count
                ? StripHtml(snippets[i].Groups["snippet"].Value).Trim()
                : "";

            // DuckDuckGo wraps URLs in a redirect; extract the actual URL
            var actualUrl = ExtractRedirectUrl(href) ?? href;

            sb.AppendLine($"{count}. {title}");
            sb.AppendLine($"   URL: {actualUrl}");
            if (!string.IsNullOrWhiteSpace(snippet))
                sb.AppendLine($"   {snippet}");
            sb.AppendLine();
        }

        return count > 0
            ? sb.ToString()
            : "No results found. Try a different search query.";
    }

    private static string? ExtractRedirectUrl(string href)
    {
        // DuckDuckGo uses //duckduckgo.com/l/?uddg=<encoded_url>&...
        if (href.Contains("uddg="))
        {
            var match = Regex.Match(href, @"uddg=(?<url>[^&]+)");
            if (match.Success)
                return Uri.UnescapeDataString(match.Groups["url"].Value);
        }

        return null;
    }

    private static string StripHtml(string html)
    {
        var text = Regex.Replace(html, @"<script[^>]*>.*?</script>", " ", RegexOptions.Singleline);
        text = Regex.Replace(text, @"<style[^>]*>.*?</style>", " ", RegexOptions.Singleline);
        text = Regex.Replace(text, @"<[^>]+>", " ");
        text = WebUtility.HtmlDecode(text);
        text = Regex.Replace(text, @"\s+", " ");
        return text.Trim();
    }
}

