+    private static string? ExtractRedirectUrl(string href)
+    {
+        // DuckDuckGo uses //duckduckgo.com/l/?uddg=<encoded_url>&...
+        if (href.Contains("uddg="))
+        {
+            var match = Regex.Match(href, @"uddg=(?<url>[^&]+)");
+            if (match.Success)
+                return Uri.UnescapeDataString(match.Groups["url"].Value);
+        }
+
+        return null;
+    }
+
+    private static string StripHtml(string html)
+    {
+        var text = Regex.Replace(html, @"<script[^>]*>.*?</script>", " ", RegexOptions.Singleline);
+        text = Regex.Replace(text, @"<style[^>]*>.*?</style>", " ", RegexOptions.Singleline);
+        text = Regex.Replace(text, @"<[^>]+>", " ");
+        text = WebUtility.HtmlDecode(text);
+        text = Regex.Replace(text, @"\s+", " ");
+        return text.Trim();
+    }
+}
