using System.ComponentModel;
using System.Text;

/// <summary>
/// In-memory note-taking tool for the research agent to record findings.
/// </summary>
public sealed class Notepad
{
    private readonly List<(string Title, string Content)> _notes = [];

    public int Count => _notes.Count;

    [Description("Save a research note to record an important finding. Use this after discovering key information.")]
    public string SaveNote(
        [Description("A short descriptive title for the note")] string title,
        [Description("The note content: key facts, data points, or observations")] string content)
    {
        _notes.Add((title, content));
        return $"Note #{_notes.Count} saved: \"{title}\"";
    }

    [Description("Retrieve all saved research notes. Use this before writing your final summary.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        for (int i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"--- Note #{i + 1}: {_notes[i].Title} ---");
            sb.AppendLine(_notes[i].Content);
            sb.AppendLine();
        }

        return sb.ToString();
    }
}

